--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelSpiritHero:OnModelInit()
	local spiritHeroEnd = GameTable.CharacterConfigRef["spiritHeroEnd"]
	local spiritHeroEndList = LUtil.ConvertCommonItemStrToList(spiritHeroEnd)
	self._spiritHeroEndList = spiritHeroEndList

	local spiritHeroEndStr
	local itemName,strTemp
	for i,v in ipairs(spiritHeroEndList) do
		itemName = gModelItem:GetNameByRefId(v.itemId)
		strTemp = v.itemNum .. "*" .. itemName
		if spiritHeroEndStr then
			spiritHeroEndStr = spiritHeroEndStr .. "," .. strTemp
		else
			spiritHeroEndStr = strTemp
		end
	end
	self._spiritHeroEndStr = spiritHeroEndStr


	self:ModelNetMsgRecv(LProtoIds.SpiritHeroViewResp,function(...) self:OnSpiritHeroViewResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.SpiritHeroLinkResp,function(...) self:OnSpiritHeroLinkResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.SpiritHeroUnlinkResp,function(...) self:OnSpiritHeroUnlinkResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.SpiritHeroLinkEndResp,function(...) self:OnSpiritHeroLinkEndResp(...) end)
end

--在协议数据处理完之后需要调用finish
function ModelSpiritHero:OnModelRequest()
	self:ModelFinish()
end

