function ModelSpiritHero:GetSpiritHeroList()
	local list = {}
	if not self:CheckIsOpenSpiritHero() then
		return list
	end

	local refId,raceType
	local heroList = gModelHero:GetHeroList()
	for id,hero in pairs(heroList) do
		refId = hero:GetRefId()
		raceType = gModelHero:GetHeroRace(refId)
		if raceType == ModelSpiritHero.SPIRITHERO_RACE then
			table.insert(list,hero:GetServerData())
		end
	end
	------ 排序
	table.sort(list,function(a,b)
		local spiritStatus1 = self:CheckSpiritHeroIsHaveLink(a) and 1 or 0
		local spiritStatus2 = self:CheckSpiritHeroIsHaveLink(b) and 1 or 0
		if spiritStatus1 ~= spiritStatus2 then
			return spiritStatus1 < spiritStatus2
		end
		return a.refId > b.refId
	end)
	return list
end

function ModelSpiritHero:GetCanSpiritHeroList(selRaceType)
	local list = {}
	selRaceType = selRaceType or 0
	local heroList = gModelHero:GetHeroList()
	local refId,raceType
	local str = GameTable.CharacterConfigRef.heroLinkCondition
	local starLim = 0
	local quaLim = 0
	if str and not string.isempty(str) then
		local strInfo = string.split(str, ",")
		starLim = tonumber(strInfo[1])
		quaLim = tonumber(strInfo[2])
	end
	if selRaceType == 0 then
		for id,hero in pairs(heroList) do
			refId = hero:GetRefId()
			raceType = gModelHero:GetHeroRace(refId)
			if raceType ~= ModelSpiritHero.SPIRITHERO_RACE then
				local quality = gModelHero:GetHeroInitQualityByRefId(hero:GetRefId())
				if hero:GetStar() >= starLim and quality >= quaLim then
					table.insert(list,hero:GetServerData())
				end
			end
		end
	else
		for id,hero in pairs(heroList) do
			refId = hero:GetRefId()
			raceType = gModelHero:GetHeroRace(refId)
			if raceType == selRaceType and raceType ~= ModelSpiritHero.SPIRITHERO_RACE then
				local quality = gModelHero:GetHeroInitQualityByRefId(hero:GetRefId())
				if hero:GetStar() >= starLim and quality >= quaLim then
					table.insert(list,hero:GetServerData())
				end
			end
		end
	end
	------ 排序
	table.sort(list,function(hero1,hero2)
		local isSelSpirit1 = self:CheckHeroIsHaveLink(hero1) and 1 or 0
		local isSelSpirit2 = self:CheckHeroIsHaveLink(hero2) and 1 or 0
		if isSelSpirit1 ~= isSelSpirit2 then
			return isSelSpirit1 < isSelSpirit2
		end
		local star1,star2 = hero1.star,hero2.star
		if star1 ~= star2 then
			return star1 > star2
		end
		local lv1,lv2 = hero1.lv,hero2.lv
		if lv1 ~= lv2 then
			return lv1 > lv2
		end
		return hero1.refId < hero2.refId
	end)
	return list
end

function ModelSpiritHero:GetShowAttrList(oldSpiritHero,newSpiritHero)
	if not oldSpiritHero or not newSpiritHero then return {} end

	local oldSpiritShowList = oldSpiritHero.showList or {}
	local newSpiritShowList = newSpiritHero.showList or {}

	local keyList = {}
	local attrType
	for i,v in ipairs(oldSpiritShowList) do
		attrType = v.attrType
		local attrTypeInfo = keyList[attrType]
		if not attrTypeInfo then
			attrTypeInfo = {}
			keyList[attrType] = attrTypeInfo
		end
		attrTypeInfo.attrName = v.attrName
		attrTypeInfo.oldValue = v.value
		attrTypeInfo.sort = v.sort
	end

	for i,v in ipairs(newSpiritShowList) do
		attrType = v.attrType
		local attrTypeInfo = keyList[attrType]
		if attrTypeInfo then
			attrTypeInfo.newValue = v.value
		else
			attrTypeInfo = {
				attrName = v.attrName,
				oldValue = 0,
				newValue = v.value,
				sort = v.sort,
			}
			keyList[attrType] = attrTypeInfo
		end
	end

	local list = {}
	for tAttrType,attrTypeInfo in pairs(keyList) do
		table.insert(list,{
			attrType = tAttrType,
			attrName = attrTypeInfo.attrName,
			oldValue = attrTypeInfo.oldValue,
			newValue = attrTypeInfo.newValue,
			sort = attrTypeInfo.sort,
		})
	end

	--- 排序
--[[	table.sort(list,function(a,b)
		return a.sort < b.sort
	end)]]

	return list
end

--- 虚空英雄已被链接，解除当前链接英雄的弹窗
function ModelSpiritHero:RelieveLinkPop(spiritHero,hero,sendMsgFunc,srcWnd)
	if not hero then
		if sendMsgFunc then sendMsgFunc() end
		return
	end
	local func = function()
		local isEnough = gModelGeneral:CheckItemListEnough(self:GetSpiritHeroEndList(),srcWnd)
		if not isEnough then return end
		if sendMsgFunc then sendMsgFunc() end
	end
	local spiritHeroEndStr = self._spiritHeroEndStr
	 local heroName = gModelHero:GetHeroNameById(hero.id)
	gModelGeneral:OpenUIOrdinTips({refId = 10031,func = func,para = { spiritHeroEndStr,heroName }})
end

