function ModelSpiritHero:IsSpiritHeroRaceType(raceType)
	if not raceType then return false end
	if raceType == ModelSpiritHero.SPIRITHERO_RACE then
		return true
	end
	return false
end

function ModelSpiritHero:CheckIsSpiritHero(refId)
	local raceType = gModelHero:GetHeroRace(refId)
	return self:IsSpiritHeroRaceType(raceType)
end

function ModelSpiritHero:GetSpiritLinkHeroRace(spiritHeroId)
	local spiritHeroServerData = gModelHero:GetHeroServerDataById(spiritHeroId)
	if not spiritHeroServerData then return end
	if not self:CheckSpiritHeroIsHaveLink(spiritHeroServerData) then return end
	local spiritLinkId = self:GetSpiritHeroLinkId(spiritHeroServerData)
	if not spiritLinkId then return end
	local spiritLinkHeroServerData = gModelHero:GetHeroServerDataById(spiritLinkId)
	if not spiritLinkHeroServerData then return end
	return gModelHero:GetHeroRace(spiritLinkHeroServerData.refId)
end


