---------------------- resp ----------------------
function ModelSpiritHero:OnSpiritHeroViewResp(pb)
	local spiritHeroId = pb.spiritHeroId
	local heroId = pb.heroId
	local oldSpiritHero = self:GetSpiritHeroViewInfoServerData(pb.oldSpiritHero)
	local newSpiritHero = self:GetSpiritHeroViewInfoServerData(pb.newSpiritHero)
	GF.OpenWnd("UISpiritSagaPreviewView",{
		spiritHeroId = spiritHeroId,
		heroId = heroId,
		oldSpiritHero = oldSpiritHero,
		newSpiritHero = newSpiritHero,
	})
end

function ModelSpiritHero:OnSpiritHeroLinkResp(pb)

	if pb.leaveFormation == 1 then
		GF.ShowMessage(ccClientText(31237))
	end
end

function ModelSpiritHero:OnSpiritHeroUnlinkResp(pb)
	GF.ShowMessage(ccClientText(31235))
	FireEvent("OnSpiritHeroUnlinkResp")
end

function ModelSpiritHero:OnSpiritHeroLinkEndResp(pb)
	local spiritHeroId = pb.spiritHeroId
	local spiritHeroServerData = gModelHero:GetHeroServerDataById(spiritHeroId)
	if not spiritHeroServerData then return end
	local heroName = gModelHero:GetHeroNameById(spiritHeroId)
	local str = string.replace(ccClientText(31229),heroName)
	GF.ShowMessage(str)
end
